public class Solution {
    public bool IsPalindrome(string s) {
        // Your solution here

        int i = 0;
        int len = s.Length;
        int j = len-1;

        if(len <2){
            return true;
        }

        while(i<j){

            while(i < j && !char.IsLetterOrDigit(s[i])){
                i++;
            }

            while(i < j && !char.IsLetterOrDigit(s[j]) ){
                j--;
            }

            if( char.ToLower(s[i])!=char.ToLower(s[j])){
                return false;
            }
            i++;
            j--;
        }

        return true;
    }
}

