public class Solution {
    public int LongestConsecutive(int[] nums) {
        // Your solution here
        HashSet<int> hashSet = GetUniquNumsInArr(nums);

        if(nums.Length==0){
            return 0;
        }

        int maxSeqLen = 1;

        for (int i = 0; i < nums.Length; i++) {

            // if not start of sequnce skip
            if(hashSet.Contains(nums[i]-1)){
                continue;
            }
            else{
                int currSeqLen = 1;
                int pointer = 1;

                while(hashSet.Contains(nums[i]+pointer)){
                    currSeqLen++;
                    pointer++;
                }
                maxSeqLen=Math.Max(currSeqLen, maxSeqLen);
            }
        }

        return maxSeqLen;
    }

    public static HashSet<int> GetUniquNumsInArr(int[] nums){

        HashSet<int> hashSet = new HashSet<int>();

        foreach (var num in nums)
        {
            hashSet.Add(num);
        }

        return hashSet;
    }
}

