public class Solution {
    public int[] ProductExceptSelf(int[] nums) {
        // Your solution here

        int[]leftProdArr = GetProductToLeft(nums);

        int[]rightProdArr=GetProductToRight(nums);

        int[] answer = new int[nums.Length];

        for (int i = 0; i < nums.Length; i++) {
            answer[i]=leftProdArr[i]*rightProdArr[i];
        }

        return answer;
    }

    public static int[] GetProductToLeft(int[] nums){

        int[] leftProdArr = new int[nums.Length];

        leftProdArr[0]=1;

        for (int i = 1; i < nums.Length; i++)
        {
            leftProdArr[i]=leftProdArr[i-1]*nums[i-1];
        }

        return leftProdArr;
    }

    public static int[] GetProductToRight(int[] nums){

        int[] rightProdArr = new int[nums.Length];

        rightProdArr[nums.Length-1]=1;

        for (int i = nums.Length-2; i >= 0; i--)
        {
            rightProdArr[i]=rightProdArr[i+1]*nums[i+1];
        }

        return rightProdArr;
    }
}

class Program {
    static void Main() {
        var sol = new Solution();
        var r1 = sol.ProductExceptSelf(new int[]{1,2,3,4});
        Console.WriteLine(string.Join(",", r1)); // 24,12,8,6
